import { useModalStore } from "./modalStore";

let idCounter = 0

function useModal() {
    const open = useModalStore((state) => state?.openModal)
    const close = useModalStore((state) => state?.closeModal)
    const openModal = ({ component, priority }) => {
        const id = `modal_${idCounter++}`
        open({
            id, component, priority
        })
        return id
    }
    return {
        openModal,
        closeModal: close
    }
}

export default useModal
